/**
 * Lint Extension for Pi
 *
 * Runs ESLint and Prettier checks after every turn. Injects lint errors
 * as messages so the agent is aware of them and can address them.
 *
 * Configuration (environment variables):
 *   LINT_SCRIPT - npm script for lint checks (default: "lint:check")
 *   FORMAT_SCRIPT - npm script for format checks (default: "format")
 *   DISABLE_LINT - set to "true" to disable lint checks
 *   DISABLE_FORMAT - set to "true" to disable format checks
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Text, Markdown } from "@mariozechner/pi-tui";

// Configuration
const lintScript = process.env.LINT_SCRIPT ?? "lint:check";
const formatScript = process.env.FORMAT_SCRIPT ?? "format";
const disableLint = process.env.DISABLE_LINT === "true";
const disableFormat = process.env.DISABLE_FORMAT === "true";

interface LintResult {
  passed: boolean;
  output: string;
  script: string;
}

async function runLintCheck(pi: ExtensionAPI, script: string): Promise<LintResult> {
  if (!script) {
    return { passed: true, output: "", script: "" };
  }

  const result = await pi.exec("npm", ["run", script]);
  return {
    passed: result.code === 0,
    output: result.stdout + result.stderr,
    script,
  };
}

function formatLintOutput(result: LintResult): string {
  if (result.passed) {
    return `✅ **${result.script}** passed`;
  }

  // Truncate output to avoid overwhelming the LLM (keep last 100 lines)
  const lines = result.output.split("\n");
  const truncated = lines.length > 100 ? lines.slice(-100) : lines;
  const truncatedOutput = truncated.join("\n");

  let formatted = `❌ **${result.script}** failed:\n\n\`\`\`\n${truncatedOutput}`;

  if (lines.length > 100) {
    formatted += `\n\n[Output truncated: ${lines.length - 100} more lines]`;
  }

  formatted += "\n```";
  return formatted;
}

export default function lintExtension(pi: ExtensionAPI) {
  // Register custom message renderer for lint errors
  pi.registerMessageRenderer("lint-errors", (message, options, theme) => {
    const { expanded } = options;
    let text = theme.fg("error", `⚠️  Lint/Format Issues\n`);
    text += message.content;

    if (expanded && message.details) {
      text += "\n" + theme.fg("dim", JSON.stringify(message.details, null, 2));
    }

    return new Text(text, 0, 0);
  });

  // Run lint/format checks after each turn
  pi.on("turn_end", async (_event, ctx) => {
    const results: LintResult[] = [];

    // Run lint check
    if (!disableLint && lintScript) {
      const lintResult = await runLintCheck(pi, lintScript);
      results.push(lintResult);
    }

    // Run format check
    if (!disableFormat && formatScript) {
      const formatResult = await runLintCheck(pi, formatScript);
      results.push(formatResult);
    }

    if (results.length === 0) {
      return; // Nothing to check
    }

    const allPassed = results.every((r) => r.passed);

    if (allPassed) {
      if (ctx.hasUI) {
        ctx.ui.notify("Lint & format checks passed", "info");
      }
      return;
    }

    // Build the error message for the agent
    const errorMessages = results
      .filter((r) => !r.passed)
      .map(formatLintOutput)
      .join("\n\n");

    // Inject the lint errors as a message so the LLM is aware
    pi.sendMessage(
      {
        customType: "lint-errors",
        content: errorMessages,
        display: true,
        details: {
          failedScripts: results.filter((r) => !r.passed).map((r) => r.script),
        },
      },
      {
        deliverAs: "steer",
        triggerTurn: false, // Don't trigger a new turn, just add context for next user input
      },
    );

    // Also show a notification
    if (ctx.hasUI) {
      const failedCount = results.filter((r) => !r.passed).length;
      ctx.ui.notify(
        `Lint/format issues detected (${failedCount} check${failedCount > 1 ? "s" : ""} failed)`,
        "warning",
      );
    }
  });

  // Register a command to manually run lint checks
  pi.registerCommand("lint", {
    description: "Run lint and format checks",
    handler: async (_args, ctx) => {
      if (ctx.hasUI) {
        ctx.ui.notify("Running lint checks...", "info");
      }

      const results: LintResult[] = [];

      if (!disableLint && lintScript) {
        const lintResult = await runLintCheck(pi, lintScript);
        results.push(lintResult);
      }

      if (!disableFormat && formatScript) {
        const formatResult = await runLintCheck(pi, formatScript);
        results.push(formatResult);
      }

      const allPassed = results.every((r) => r.passed);

      if (allPassed) {
        if (ctx.hasUI) {
          ctx.ui.notify("All checks passed!", "info");
        }
        return;
      }

      // Show the full output for manual runs
      const errorMessages = results
        .filter((r) => !r.passed)
        .map(formatLintOutput)
        .join("\n\n");

      pi.sendMessage(
        {
          customType: "lint-errors",
          content: errorMessages,
          display: true,
        },
        { triggerTurn: false },
      );

      if (ctx.hasUI) {
        ctx.ui.notify(`Lint check failed - see above for details`, "error");
      }
    },
  });
}

