    const failed = results.filter((r) => !r.passed);
    if (failed.length === 0) return;

    const errors = formatOutput(failed);

    pi.sendMessage(
      {
        customType: "lint-errors",
        content: errors,
        display: true,
      },
      { deliverAs: "steer", triggerTurn: true },
    );

    if (ctx.hasUI) {
